# LCM Simple

## 问题描述

实现一个函数，输入两个正整数 `a` 和 `b`，返回它们的最小公倍数。

约定：

- `a > 0`
- `b > 0`
- 使用简单枚举，从 `a` 开始每次加 `a`，直到找到能被 `b` 整除的数

## 正确代码

```c
int lcm_simple(int a, int b) {
    int x = a;

    while (x % b != 0) {
        x = x + a;
    }

    return x;
}
```

## 说明

这是最简单的最小公倍数枚举题，适合验证“循环保持倍数 + 找到整除条件”。

#include "../../verification_stdlib.h"

/*@ Extern Coq (gcd_iterative_spec: Z -> Z -> Z -> Prop) */
/*@ Import Coq Require Import gcd_iterative */

int gcd_iterative(int a, int b)
/*@ Require
      0 <= a &&
      0 <= b &&
      0 < a + b &&
      emp
    Ensure
      gcd_iterative_spec(a@pre, b@pre, __return) && emp
*/
{
    int r;

    while (b != 0) {
        r = a % b;
        a = b;
        b = r;
    }

    return a;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (count_divisors_spec : Z -> Z) */
/*@ Import Coq Require Import count_divisors */

int count_divisors(int n)
/*@ Require
      1 <= n && n < INT_MAX && emp
    Ensure
      __return == count_divisors_spec(n@pre) && emp
*/
{
    int d;
    int cnt = 0;

    for (d = 1; d <= n; ++d) {
        if (n % d == 0) {
            cnt++;
        }
    }

    return cnt;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (power_nonnegative_z: Z -> Z -> Z) */
/*@ Import Coq Require Import power_nonnegative */

int power_nonnegative(int base, int exp)
/*@ Require
      0 <= exp &&
      (forall (k: Z), (0 <= k && k <= exp) =>
        (INT_MIN <= power_nonnegative_z(base, k) &&
         power_nonnegative_z(base, k) <= INT_MAX)) &&
      emp
    Ensure
      __return == power_nonnegative_z(base@pre, exp@pre) && emp
*/
{
    int i;
    int ans = 1;

    for (i = 0; i < exp; ++i) {
        ans = ans * base;
    }

    return ans;
}

#include "../../verification_stdlib.h"

/*@ Extern Coq (lcm_simple_value: Z -> Z -> Z)
               (lcm_simple_spec: Z -> Z -> Z -> Prop) */
/*@ Import Coq Require Import lcm_simple */

int lcm_simple(int a, int b)
/*@ Require
      1 <= a &&
      1 <= b &&
      lcm_simple_value(a, b) <= INT_MAX &&
      emp
    Ensure
      lcm_simple_spec(a@pre, b@pre, __return) && emp
*/
{
    int x = a;

    while (x % b != 0) {
        x = x + a;
    }

    return x;
}
Require Import ZArith.

Open Scope Z_scope.

Definition lcm_simple_value (a b : Z) : Z :=
  Z.lcm a b.

Definition lcm_simple_spec (a b r : Z) : Prop :=
  r = lcm_simple_value a b.
